mapper.select:
SELECT id, user_id, warn_type, proc_inst_id, node_key, node_name, end_date, is_read, create_time
FROM task_warning
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

mapper.update:
UPDATE task_warning
SET is_read = 1
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM task_warning
WHERE user_id = #{userId}
  AND proc_inst_id = #{procInstId}
  AND node_key = #{nodeKey}
  AND warn_type = #{warnType}

mapper.update:
UPDATE task_warning
SET is_read = 1
WHERE proc_inst_id = #{procInstId}
  AND node_key = #{nodeKey}
  AND is_read = 0
